using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// ── 1. GetTypeInfo<T>() — strongly-typed metadata ──
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 38), personInfo);
Console.WriteLine($"  Serialized: {json}");

// ── 2. TryGetTypeInfo<T>() — check without throwing ──

// Case A: type that IS resolvable
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
    Console.WriteLine($"TryGetTypeInfo<Person>  → found ({found!.Type.Name})");
else
    Console.WriteLine("TryGetTypeInfo<Person>  → not found");

// Case B: use a resolver that resolves nothing, so the probe returns false
var empty = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver
    {
        Modifiers = { (ti) => throw new NotSupportedException() }
    }
};

if (empty.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? missed))
    Console.WriteLine($"TryGetTypeInfo<Person> (empty resolver) → found ({missed!.Type.Name})");
else
    Console.WriteLine("TryGetTypeInfo<Person> (empty resolver) → not found (no exception!)");

public record Person(string Name, int Age);

